.dropdown {
  --animation: slideDown;
  --animation-time: 0.3s;
  width: 500px;
  position: relative;
  display: grid;
  place-content: center;
  margin: 16px auto 90px auto;
}

.dropdown button {
  background: white;
  color:black;
  width: 200px;
  border: none;
  padding: 8px;
  cursor: pointer;
  border-radius: 6px;
}

.dropdown .dropdown-container {
  --margin-dropdown: 20px;
  width: 50%;
  position: absolute;
  top: calc(100% + var(--margin-dropdown));
  left: 0;
  transform: translate(50%, 0%);
  z-index: 10;
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  interpolate-size: allow-keywords;
}

.dropdown .dropdown-container::before {
  content: "";
  position: absolute;
  top: calc(0% - var(--margin-dropdown));
  left: 0;
  width: 100%;
  height: var(--margin-dropdown);
}

.dropdown ol {
  list-style: none;
  padding: 0;
  margin: 0;
}

.dropdown li {
  width: 100%;
  padding: 8px;
  border-bottom: 1px solid var(--outline-variant);
}

.dropdown li:hover {
  background: #09f;
}

.dropdown li:hover a {
  color: var(--on-primary);
}

.dropdown a {
  text-decoration: none;
  color: var(--on-surface-container);
  display: block;
}

.dropdown button:hover + .dropdown-container,
.dropdown button:focus + .dropdown-container,
.dropdown .dropdown-container:hover {
  visibility: visible;
   opacity: 1;
  pointer-events: all;
  background: white;
  animation: var(--animation) var(--animation-time) ease forwards;
}
